DROP TABLE IF EXISTS `qiswl_member`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `qiswl_member` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `username` varchar(255) DEFAULT NULL COMMENT '用户名',
  `password` varchar(255) DEFAULT NULL COMMENT '密码',
  `register_time` int unsigned DEFAULT '0' COMMENT '注册时间',
  `country_code` varchar(10) DEFAULT '' COMMENT '国家区号',
  `phone` varchar(30) DEFAULT '' COMMENT '手机号',
  `email` varchar(100) DEFAULT '' COMMENT '邮箱',
  `last_time` int DEFAULT '0' COMMENT '最后登录时间',
  `isvip_status` tinyint unsigned DEFAULT '0' COMMENT 'vip状态:1=是,0=否',
  `viptime` varchar(15) DEFAULT '0' COMMENT 'vip到期时间',
  `headimage` varchar(255) DEFAULT '' COMMENT '头像',
  `status` tinyint unsigned DEFAULT '1' COMMENT '状态:1=正常,0=冻结',
  `score` int unsigned DEFAULT '0' COMMENT '书币',
  `pid` int unsigned DEFAULT '0' COMMENT '上级ID',
  `register_ip` varchar(100) DEFAULT '' COMMENT '注册ip',
  `login_ip` varchar(100) DEFAULT '' COMMENT '登录IP',
  `login_nums` int unsigned DEFAULT '0' COMMENT '登录次数',
  `useragent` varchar(255) DEFAULT '' COMMENT '用户客户端信息',
  `type` tinyint unsigned DEFAULT '0' COMMENT '类别:0=临时,1=注册',
  `myui` varchar(255) DEFAULT 'color-theme-pink' COMMENT '个人皮肤',
  `is_first` int unsigned DEFAULT '1' COMMENT '是否第一次',
  `reason` varchar(200) DEFAULT '' COMMENT '冻结原因',
  `token` varchar(100) DEFAULT '' COMMENT 'token',
  `token_val` int unsigned DEFAULT '0',
  `auto_buy` tinyint unsigned DEFAULT '0',
  `code` varchar(20) DEFAULT '',
  `discount_time` int unsigned DEFAULT '0' COMMENT '折扣时间',
  `nickname` varchar(255) DEFAULT '',
  `avatar` varchar(255) DEFAULT '',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `username` (`username`) USING BTREE,
  KEY `useragent` (`useragent`) USING BTREE,
  KEY `token` (`token`) USING BTREE,
  KEY `code` (`code`) USING BTREE
) ENGINE=MyISAM AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb3 ROW_FORMAT=DYNAMIC;
