DROP TABLE IF EXISTS `qiswl_paymanger`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `qiswl_paymanger` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `qudaokey` varchar(255) DEFAULT '' COMMENT '渠道key',
  `qudaoname` varchar(255) DEFAULT '' COMMENT '名称',
  `qudaonum` varchar(20) DEFAULT '' COMMENT '渠道编码',
  `qudaosort` int unsigned DEFAULT '99' COMMENT '排序',
  `qudaomoney` varchar(100) DEFAULT '-' COMMENT '金额',
  `qudaodes` varchar(255) DEFAULT '' COMMENT '备注',
  `qudaopaydata` tinyint(1) DEFAULT '1' COMMENT '支付方式:1=支付宝,2=微信,3=行用卡/借记卡',
  `qudaoswitch` tinyint(1) DEFAULT '0' COMMENT '状态:0=关闭,1=开启',
  `config` text,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=COMPACT;
/*!40101 SET character_set_client = @saved_cs_client */;

