--
-- Table structure for table `system_log`
--

DROP TABLE IF EXISTS `system_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `system_log` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `title` varchar(255) DEFAULT '' COMMENT '操作菜单',
  `user_id` int unsigned DEFAULT '0' COMMENT '会员ID->user',
  `routes` varchar(255) DEFAULT '' COMMENT '操作路由',
  `content` text,
  `ip` varchar(20) DEFAULT '' COMMENT 'ip',
  `address` varchar(255) DEFAULT '' COMMENT '操作地址',
  `created_at` int unsigned DEFAULT '0' COMMENT '操作时间',
  `admin_id` int unsigned DEFAULT '0' COMMENT '操作人id->admin',
  `status` tinyint unsigned DEFAULT '1' COMMENT '状态 1正常 2异常',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `cid_dex` (`user_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=18043 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='系统日志表';
/*!40101 SET character_set_client = @saved_cs_client */;

