CREATE TABLE `translation_tasks` (
  `id` int NOT NULL AUTO_INCREMENT,
  `type` varchar(255) NOT NULL COMMENT '类型:题材,标签',
  `type_id` int unsigned NOT NULL COMMENT '类型ID',
  `lang_code` varchar(10) NOT NULL COMMENT '语言代码，如 ''en'', ''jp'', ''th''',
  `field` varchar(255) DEFAULT '' COMMENT '标题',
  `origin_text` text COMMENT '原文',
  `translated_text` text COMMENT '译文',
  `status` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '翻译状态:0=处理中,1=成功,2=失败',
  `error_message` varchar(255) DEFAULT '' COMMENT '错误信息',
  `retry_count` int DEFAULT '0',
  `update_time` int DEFAULT '0' COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=6941 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
